// Extrai e valida mensagem recebida da Evolution API
const body = $input.first().json;

if (body.event !== 'messages.upsert') return [];
const data = body.data;
if (data?.key?.fromMe) return [];
if (data?.key?.remoteJid?.includes('@g.us')) return [];

const phone = data.key.remoteJid.replace('@s.whatsapp.net', '');
const messageType = data.messageType;
const instanceName = body.instance;

let rawText = '';
let isAudio = false;

if (messageType === 'conversation') {
  rawText = data.message?.conversation || '';
} else if (messageType === 'extendedTextMessage') {
  rawText = data.message?.extendedTextMessage?.text || '';
} else if (['audioMessage', 'pttMessage'].includes(messageType)) {
  isAudio = true;
} else {
  return [];
}

if (!rawText && !isAudio) return [];

return [{ json: { phone, messageType, rawText, isAudio, instanceName, messageData: data } }];

// Converte base64 da Evolution API para item binário para enviar ao Groq
const audioData = $input.first().json;
const base64 = audioData.base64;
const mimetype = (audioData.mimetype || 'audio/ogg').split(';')[0];

return [{
  json: {
    phone: $('Extrair Mensagem').first().json.phone,
    instanceName: $('Extrair Mensagem').first().json.instanceName
  },
  binary: {
    audioFile: {
      data: base64,
      mimeType: mimetype,
      fileName: 'audio.ogg'
    }
  }
}];

const phone = $('Merge Texto').first().json.phone;
const instanceName = $('Merge Texto').first().json.instanceName;
const texto = $('Merge Texto').first().json.texto;

let historico = [];
try {
  const val = $('Ler Histórico Redis').first().json.value;
  if (val) historico = JSON.parse(val);
} catch(e) { historico = []; }

const systemPrompt = `Você é o secretário pessoal do Guilherme Faustino da Silva.

PERFIL:
- Maringá/PR
- Frentes ativas: Clube do Gole (validação Sebrae/Impulso Maringá), Secretario (app Node/React/PostgreSQL/Docker), curso ADS no CEEP, trabalho corporativo (gestão financeira/contratos)
- Dispositivos: iPhone 14, PC desktop (Windows), notebook

COMPORTAMENTO:
- Respostas curtas no WhatsApp — máximo 3 linhas salvo pedido explícito
- Confirme SEMPRE antes de executar ações irreversíveis (delete, envio de email, deploy)
- Português brasileiro, tom direto
- Mantenha contexto das últimas 20 mensagens

Documentos mapeados no Drive:
{
  "tracker": "ID_TRACKER",
  "cronograma": "ID_CRONOGRAMA",
  "participacao": "ID_IMPULSO_MARINGA"
}

Projetos SSH:
{
  "secretario": { "path": "/path/to/secretario", "portas": [3000, 5173, 8080, 5432] },
  "clube-do-gole": { "path": "/path/to/clube-do-gole" }
}

Responda SEMPRE em JSON válido:
{
  "intencao": "chat|tarefa|agenda|drive|email|codigo|deploy|doc",
  "resposta": "texto para o usuário (máx 3 linhas)",
  "acao": {
    "tipo": "nenhuma|criar_evento|ler_doc|escrever_doc|ler_email|arquivar_email|enviar_email|executar_ssh|deploy",
    "params": {}
  },
  "confirmacao_necessaria": false
}`;

const mensagens = [...historico, { role: 'user', content: texto }].slice(-40);

// OpenRouter usa formato OpenAI: system entra como primeira mensagem
const messagesComSystem = [{ role: 'system', content: systemPrompt }, ...mensagens];

return [{
  json: {
    phone, instanceName, texto,
    payload: {
      model: $env.OPENROUTER_MODEL || 'anthropic/claude-3.5-haiku',
      max_tokens: 1024,
      messages: messagesComSystem
    },
    historico: mensagens
  }
}];

const phone = $('Montar Payload Claude').first().json.phone;
const instanceName = $('Montar Payload Claude').first().json.instanceName;
const historico = $('Montar Payload Claude').first().json.historico;

const resp = $input.first().json;
const content = resp.choices?.[0]?.message?.content || resp.error?.message || '';

let parsed;
try {
  // Remove possível markdown em volta do JSON
  const clean = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { intencao: 'chat', resposta: content, acao: { tipo: 'nenhuma', params: {} }, confirmacao_necessaria: false };
}

const historicoAtualizado = [...historico, { role: 'assistant', content }].slice(-40);

return [{
  json: {
    phone, instanceName,
    intencao: parsed.intencao || 'chat',
    resposta: parsed.resposta || content,
    acao: parsed.acao || { tipo: 'nenhuma', params: {} },
    confirmacao_necessaria: parsed.confirmacao_necessaria || false,
    historicoAtualizado: JSON.stringify(historicoAtualizado)
  }
}];

// Renovar token Google antes de chamar APIs
const resp = await fetch('https://oauth2.googleapis.com/token', {
  method: 'POST',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: new URLSearchParams({
    client_id: $env.GOOGLE_CLIENT_ID,
    client_secret: $env.GOOGLE_CLIENT_SECRET,
    refresh_token: $env.GOOGLE_REFRESH_TOKEN,
    grant_type: 'refresh_token'
  })
});
const token = await resp.json();

const params = $json.acao?.params || {};
const tipo = $json.acao?.tipo || 'criar_evento';

let respostaExtra = '';

if (tipo === 'criar_evento') {
  const inicio = new Date(`${params.data}T${params.hora || '09:00'}:00-03:00`);
  const fim = new Date(inicio.getTime() + (params.duracao || 60) * 60000);
  const evento = {
    summary: params.titulo || 'Evento',
    description: params.descricao || '',
    start: { dateTime: inicio.toISOString(), timeZone: 'America/Sao_Paulo' },
    end: { dateTime: fim.toISOString(), timeZone: 'America/Sao_Paulo' }
  };
  const r = await fetch('https://www.googleapis.com/calendar/v3/calendars/primary/events', {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${token.access_token}`, 'Content-Type': 'application/json' },
    body: JSON.stringify(evento)
  });
  const ev = await r.json();
  respostaExtra = ev.id ? `✅ Evento criado: ${ev.summary} — ${params.data} às ${params.hora}` : `❌ Erro ao criar evento`;
} else if (tipo === 'consultar_agenda') {
  const hoje = new Date();
  const amanha = new Date(hoje);
  amanha.setDate(amanha.getDate() + 1);
  const r = await fetch(`https://www.googleapis.com/calendar/v3/calendars/primary/events?timeMin=${hoje.toISOString()}&timeMax=${amanha.toISOString()}&singleEvents=true&orderBy=startTime`, {
    headers: { 'Authorization': `Bearer ${token.access_token}` }
  });
  const data = await r.json();
  const eventos = data.items || [];
  respostaExtra = eventos.length === 0 ? 'Sem eventos hoje.' : eventos.map(e => `• ${e.summary} — ${new Date(e.start.dateTime || e.start.date).toLocaleTimeString('pt-BR', {hour:'2-digit',minute:'2-digit'})}`).join('\n');
}

return [{ json: { ...$json, respostaFinal: respostaExtra || $json.resposta } }];

// Handler Google Drive — lê ou escreve documentos
const tokenResp = await fetch('https://oauth2.googleapis.com/token', {
  method: 'POST',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: new URLSearchParams({
    client_id: $env.GOOGLE_CLIENT_ID,
    client_secret: $env.GOOGLE_CLIENT_SECRET,
    refresh_token: $env.GOOGLE_REFRESH_TOKEN,
    grant_type: 'refresh_token'
  })
});
const { access_token } = await tokenResp.json();

const DOCS = {
  tracker: 'ID_TRACKER',
  cronograma: 'ID_CRONOGRAMA',
  participacao: 'ID_IMPULSO_MARINGA'
};

const params = $json.acao?.params || {};
const tipo = $json.acao?.tipo || 'ler_doc';
const docKey = params.doc || 'tracker';
const docId = DOCS[docKey] || params.doc_id;

let respostaFinal = '';

if (tipo === 'ler_doc' && docId) {
  const r = await fetch(`https://docs.googleapis.com/v1/documents/${docId}`, {
    headers: { 'Authorization': `Bearer ${access_token}` }
  });
  const doc = await r.json();
  const texto = doc.body?.content?.map(b => b.paragraph?.elements?.map(e => e.textRun?.content || '').join('')).join('') || '';
  respostaFinal = texto.substring(0, 500) + (texto.length > 500 ? '...' : '');
} else if (tipo === 'escrever_doc' && docId) {
  // Append texto ao documento
  const conteudo = params.conteudo || '';
  const r = await fetch(`https://docs.googleapis.com/v1/documents/${docId}:batchUpdate`, {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${access_token}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      requests: [{ insertText: { location: { index: 1 }, text: `\n${conteudo}\n` } }]
    })
  });
  const ok = r.ok;
  respostaFinal = ok ? `✅ Doc atualizado: ${docKey}` : '❌ Erro ao atualizar doc';
  if (ok) {
    // Marca documentação do dia como feita
    // (Redis — salvo no próximo node se necessário)
  }
}

return [{ json: { ...$json, respostaFinal: respostaFinal || $json.resposta } }];

// Handler Gmail
const tokenResp = await fetch('https://oauth2.googleapis.com/token', {
  method: 'POST',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: new URLSearchParams({
    client_id: $env.GOOGLE_CLIENT_ID,
    client_secret: $env.GOOGLE_CLIENT_SECRET,
    refresh_token: $env.GOOGLE_REFRESH_TOKEN,
    grant_type: 'refresh_token'
  })
});
const { access_token } = await tokenResp.json();

const params = $json.acao?.params || {};
const tipo = $json.acao?.tipo || 'ler_email';
let respostaFinal = '';

if (tipo === 'ler_email') {
  const limite = params.limite || 5;
  const r = await fetch(`https://gmail.googleapis.com/gmail/v1/users/me/messages?maxResults=${limite}&q=is:unread`, {
    headers: { 'Authorization': `Bearer ${access_token}` }
  });
  const data = await r.json();
  const msgs = data.messages || [];
  if (msgs.length === 0) { respostaFinal = 'Nenhum email não lido.'; }
  else {
    const detalhes = await Promise.all(msgs.slice(0, 5).map(async m => {
      const r2 = await fetch(`https://gmail.googleapis.com/gmail/v1/users/me/messages/${m.id}?format=metadata&metadataHeaders=From&metadataHeaders=Subject`, {
        headers: { 'Authorization': `Bearer ${access_token}` }
      });
      const msg = await r2.json();
      const headers = msg.payload?.headers || [];
      const from = headers.find(h => h.name === 'From')?.value || '?';
      const subject = headers.find(h => h.name === 'Subject')?.value || '?';
      return `• ${from.split('<')[0].trim()} — ${subject}`;
    }));
    respostaFinal = `📧 ${msgs.length} não lido(s):\n${detalhes.join('\n')}`;
  }
} else if (tipo === 'arquivar_email') {
  const remetente = params.remetente || '';
  const r = await fetch(`https://gmail.googleapis.com/gmail/v1/users/me/messages?q=from:${encodeURIComponent(remetente)}`, {
    headers: { 'Authorization': `Bearer ${access_token}` }
  });
  const data = await r.json();
  const ids = (data.messages || []).map(m => m.id);
  if (ids.length > 0) {
    await fetch('https://gmail.googleapis.com/gmail/v1/users/me/messages/batchModify', {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${access_token}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ ids, removeLabelIds: ['INBOX'] })
    });
    respostaFinal = `✅ ${ids.length} email(s) de "${remetente}" arquivado(s).`;
  } else {
    respostaFinal = `Nenhum email encontrado de "${remetente}".`;
  }
}

return [{ json: { ...$json, respostaFinal: respostaFinal || $json.resposta } }];

// Handler Deploy via SSH (Tailscale)
const params = $json.acao?.params || {};
const projeto = params.projeto || 'secretario';

const PROJETOS = {
  'secretario': { path: '/path/to/secretario', portas: [3000, 5173, 8080] },
  'clube-do-gole': { path: '/path/to/clube-do-gole', portas: [3000] }
};

const proj = PROJETOS[projeto];
if (!proj) return [{ json: { ...$json, respostaFinal: `❌ Projeto "${projeto}" não mapeado.` } }];

const cmd = `cd ${proj.path} && git pull && docker compose up -d --build 2>&1 | tail -20`;

// Executa via ssh_exec.py (montado em /home/node/scripts)
const { exec } = require('child_process');
const { promisify } = require('util');
const execAsync = promisify(exec);

const sshPayload = JSON.stringify({
  host: $env.SSH_HOST,
  user: $env.SSH_USER,
  cmd: cmd
});

let respostaFinal;
try {
  const { stdout } = await execAsync(`python3 /home/node/scripts/ssh_exec.py '${sshPayload}'`);
  const result = JSON.parse(stdout);
  if (result.ok) {
    respostaFinal = `✅ Deploy ${projeto} concluído.\n${result.saida.slice(-200)}`;
  } else {
    respostaFinal = `❌ Erro no deploy ${projeto}:\n${result.erro.slice(0, 200)}`;
  }
} catch(e) {
  respostaFinal = `❌ Falha SSH: ${e.message}`;
}

return [{ json: { ...$json, respostaFinal } }];

// Handler Código — altera arquivo via SSH
const params = $json.acao?.params || {};
const cmd = params.comando || 'echo "nenhum comando"';

const { exec } = require('child_process');
const { promisify } = require('util');
const execAsync = promisify(exec);

const sshPayload = JSON.stringify({ host: $env.SSH_HOST, user: $env.SSH_USER, cmd });

let respostaFinal;
try {
  const { stdout } = await execAsync(`python3 /home/node/scripts/ssh_exec.py '${sshPayload}'`);
  const result = JSON.parse(stdout);
  respostaFinal = result.ok ? `✅ Executado:\n${result.saida.slice(0, 300)}` : `❌ Erro:\n${result.erro.slice(0, 300)}`;
} catch(e) {
  respostaFinal = `❌ Falha SSH: ${e.message}`;
}

return [{ json: { ...$json, respostaFinal } }];

// Handler Documentação — salva registro do dia no Drive
const tokenResp = await fetch('https://oauth2.googleapis.com/token', {
  method: 'POST',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: new URLSearchParams({
    client_id: $env.GOOGLE_CLIENT_ID,
    client_secret: $env.GOOGLE_CLIENT_SECRET,
    refresh_token: $env.GOOGLE_REFRESH_TOKEN,
    grant_type: 'refresh_token'
  })
});
const { access_token } = await tokenResp.json();

const hoje = new Date().toLocaleDateString('pt-BR');
const params = $json.acao?.params || {};
const frente = params.frente || 'Geral';
const conteudo = params.conteudo || $('Merge Texto').first().json.texto;

const DOCS = { tracker: 'ID_TRACKER', cronograma: 'ID_CRONOGRAMA' };
const docId = DOCS[params.doc] || DOCS.tracker;

const registro = `\n## ${hoje}\n**Frente:** ${frente}\n**O que foi feito:** ${conteudo}\n**Próximos passos:** ${params.proximos || '—'}\n`;

const r = await fetch(`https://docs.googleapis.com/v1/documents/${docId}:batchUpdate`, {
  method: 'POST',
  headers: { 'Authorization': `Bearer ${access_token}`, 'Content-Type': 'application/json' },
  body: JSON.stringify({
    requests: [{ insertText: { location: { index: 1 }, text: registro } }]
  })
});

const ok = r.ok;

// Marca documentação do dia no Redis
if (ok) {
  // Set via HTTP ao Redis não é direto — usa próximo node Redis
}

return [{ json: { ...$json, respostaFinal: ok ? `✅ Documentado em ${frente} — ${hoje}` : '❌ Erro ao salvar no Drive', docSalvo: ok } }];

// Normaliza a resposta final para envio no WhatsApp
const texto = $json.respostaFinal || $json.resposta || 'Entendido.';
return [{ json: { ...$json, respostaFinal: texto } }];
